generated_oml:
// ==== Physical Sensing Components ====
// Motor‑mounted position encoder
instance MotorMountedEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor‑mounted encoder providing angular position of the permanent‑magnet synchronous motor"
    DTDFVocab:producedData MotorEncoderDataTx
]

// Gearbox position encoder (secondary)
instance GearboxPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox providing angular position of the gearbox output shaft"
    DTDFVocab:producedData GearboxEncoderDataTx
]

// Motor current sensor (I_M)
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor reading the motor input current I_M supplied by the robot controller"
    DTDFVocab:producedData MotorCurrentDataTx
]

// Output angle sensor (controller feedback)
instance OutputAngleSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor delivering the robot controller's measured output angle of the axis"
    DTDFVocab:producedData OutputAngleDataTx
]

// ==== Data Transmitted via MQTT (Physical‑to‑Virtual Interaction) ====
instance MotorEncoderDataTx : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorMountedEncoder
]

instance GearboxEncoderDataTx : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxPositionEncoder
]

instance MotorCurrentDataTx : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance OutputAngleDataTx : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom OutputAngleSensor
]

// ==== Virtual Data (stored as DataPoints in the digital shadow) ====
instance MotorEncoderData : DTDFVocab:Data [
    base:desc "Angular position data from the motor‑mounted encoder"
    DTDFVocab:fromData MotorEncoderDataTx
    DTDFVocab:inputTo MqttEnabler
]

instance GearboxEncoderData : DTDFVocab:Data [
    base:desc "Angular position data from the gearbox encoder"
    DTDFVocab:fromData GearboxEncoderDataTx
    DTDFVocab:inputTo MqttEnabler
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Measured motor input current I_M"
    DTDFVocab:fromData MotorCurrentDataTx
    DTDFVocab:inputTo MqttEnabler
]

instance OutputAngleData : DTDFVocab:Data [
    base:desc "Measured output angle of the axis"
    DTDFVocab:fromData OutputAngleDataTx
    DTDFVocab:inputTo MqttEnabler
]

// ==== Enablers (Tooling & Integration) ====
instance MqttEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker used for streaming live sensor data from the robot to the digital shadow"
    DTDFVocab:enables FrictionIdentificationService, DataVisualizationService, FrictionParameterUpdateService
]

instance SimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink environment executing friction‑free and friction‑augmented simulation models"
    DTDFVocab:enables FrictionIdentificationService, FrictionParameterUpdateService
]

instance SysmlEnabler : DTDFVocab:Enabler [
    base:desc "SysML toolchain providing structural block definition and internal block diagrams of the robot axis"
    DTDFVocab:enables AssetModelRepository
]

instance AasEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell (AAS) enabling standardized integration of the digital shadow within the IIoT ecosystem"
    DTDFVocab:enables AssetModelRepository
]

instance DashboardEnabler : DTDFVocab:Enabler [
    base:desc "Custom dashboard for visualising measured versus simulated data and friction parameter trends"
    DTDFVocab:enables DataVisualizationService
]

// ==== Models (Engineering & Simulation) ====
instance StructuralSysmlModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagrams describing the MABI MAX 100 first axis structure"
    DTDFVocab:inputTo SysmlEnabler, AasEnabler
]

instance FrictionFreeSimulinkModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model representing the axis dynamics without gearbox friction"
    DTDFVocab:inputTo SimulinkEnabler
]

instance FrictionAugmentedSimulinkModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model including static, kinetic and viscous friction for the gearbox"
    DTDFVocab:inputTo SimulinkEnabler
]

instance DataCalculationModel : DTDFVocab:Model [
    base:desc "Model calculating derived torque τ, angular velocity ω and acceleration from measured current and positions"
    DTDFVocab:inputTo SimulinkEnabler
]

// ==== Services Provided by the Digital Shadow ====
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time identification of gearbox friction coefficients (static, kinetic, viscous) from live sensor data"
    DTDFVocab:provides FrictionParameterInsight
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Unified dashboard visualising measured versus simulated data streams for the axis"
    DTDFVocab:provides MeasuredVsSimulatedVisualizationInsight
]

instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Service that updates friction model parameters in the robot controller to improve motion accuracy"
    DTDFVocab:provides UpdateFrictionParametersAction
]

// ==== Insights & Actions ====
instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Derived static, kinetic and viscous friction coefficients identified from live data"
]

instance MeasuredVsSimulatedVisualizationInsight : DTDFVocab:Insight [
    base:desc "Insight showing the comparison between measured sensor traces and simulated model outputs"
]

instance UpdateFrictionParametersAction : DTDFVocab:Action [
    base:desc "Automatic update of friction model parameters back to the robot controller for motion control refinement"
    DTDFVocab:IsAutomatic true
]

// ==== Asset Components & Environment (Context) ====
instance PermanentMagnetSynchronousMotor : DTDFVocab:Component [
    base:desc "Permanent‑magnet synchronous motor driving the first axis of the MABI MAX 100 robot"
]

instance GearTransmission : DTDFVocab:Component [
    base:desc "Gear transmission (including cycloidal gearbox) coupling motor torque to the axis output"
]

instance CycloidalGearbox : DTDFVocab:Component [
    base:desc "Cycloidal gearbox providing high reduction and defining the friction characteristics under study"
]

instance SafetyCell : DTDFVocab:Component [
    base:desc "Safety enclosure limiting axis motion to ±90° and maximum speed 75°/s"
]

instance MabiMax100AxisEnvironment : DTDFVocab:Environment [
    base:contains PermanentMagnetSynchronousMotor, GearTransmission, CycloidalGearbox, SafetyCell
]

// ==== Asset Model Repository (logical grouping) ====
instance AssetModelRepository : DTDFVocab:Component [
    base:desc "Logical repository aggregating SysML and AAS models of the robot axis for reuse and integration"
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous, real‑time operation during robot run‑time; data are acquired and processed on‑line as the robot moves, enabling immediate identification of friction changes."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A purpose‑driven digital shadow comprising a singleton Purpose class (FrictionDerivation), an Asset class (Mabi), multiple DataTrace classes (e.g., I_M, r_M, r_G, r_out, ^r_M, ^r_G, ^r_out), Processing components (Simulation_M, Simulation_GW, Simulation_GB) that execute Simulink models, and metadata linking all traces to their sources, forming an integrated virtual replica of the first robot axis."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital shadow is instantiated and used in the operated phase of the robot, i.e., during runtime, to monitor and improve motion accuracy; engineering models are created beforehand but the primary activity is during operation."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability is ensured by linking each DataTrace to its originating source and processing component; engineering models provide contextual asset information; simulation models are executable and calibrated against live measurements; this fine‑grained traceability supports verification of model accuracy and assessment of uncertainties in friction identification."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transmitted from the robot to the digital shadow over MQTT; Asset Administration Shells (AAS) are used for structuring asset information; the digital shadow consumes these streams and produces processed traces for the dashboard."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The implementation uses the Industry 4.0 Asset Administration Shell (AAS) standard for asset description and SysML as a modelling standard; MQTT is used as a de‑facto protocol for IoT data exchange."
]
